```class Solution {
public:
    int findTheLongestBalancedSubstring(string s) {
        int n = s.length();
        int max_len = 0;
        for (int i = 0; i < n; i++) {
            int count_zero = 0, count_one = 0;
            for (int j = i; j < n; j++) {
                if (s[j] == '0') {
                    count_zero++;
                } else {
                    count_one++;
                }
                if (count_zero > count_one) {
                    max_len = max(max_len, i + count_zero - count_one);
                }
            }
        }
        return max_len;
    }
};
```

